          import sailpoint.object.Identity;
          import sailpoint.tools.Util;
          String termValue = ""; 

          if (Util.isNotNullOrEmpty(identityName)) 
          {
            Identity idn = context.getObjectByName(Identity.class, identityName);
            if (idn != null) 
            {
              Identity mgrIdentity = idn.getManager();
          		if(null!=mgrIdentity)
          		{
          			termValue = mgrIdentity.getName() +"-"+mgrIdentity.getDisplayName();
          		}
          
          		if(null!=idn)
